func TestRuntimeMirrorMarksAutomationCommandsDestructive(t *testing.T) {
	got := runtimeMirroredCommands(cli.RootCmd())

	want := []string{
		"auto_negate",
		"auto_promote",
		"budget_rebalance",
		"bid_rules_apply",
	}
	for _, name := range want {
		cmd := got[name]
		if cmd == nil {
			t.Fatalf("runtime MCP mirror is missing automation tool %q", name)
		}
		if isMCPReadOnly(cmd) {
			t.Errorf("%q must not be marked read-only because it exposes --apply", name)
		}
		if !isMCPDestructive(cmd) {
			t.Errorf("%q must be marked destructive for MCP approval flows", name)
		}
		if !isMCPOpenWorld(cmd) {
			t.Errorf("%q must be marked open-world because it targets Amazon Ads state", name)
		}
	}
}

